import json
import re
from datetime import datetime

def score_quality(data_json: str) -> str:
    data = json.loads(data_json)
    records = data["data"]
    rules = data["rules"]
    ref_date = datetime.strptime(data["reference_date"], "%Y-%m-%d")
    n = len(records)

    # Completeness: non-null fields / total fields
    total_fields = 0
    non_null = 0
    for r in records:
        for k in rules:
            total_fields += 1
            if r.get(k) is not None:
                non_null += 1
    completeness = round(non_null / total_fields, 2) if total_fields else 0

    # Uniqueness: unique IDs / total IDs
    ids = [r["id"] for r in records]
    uniqueness = round(len(set(ids)) / len(ids), 2)

    # Validity: fields passing format rules
    valid_count = 0
    validity_total = 0
    for r in records:
        for field, rule in rules.items():
            val = r.get(field)
            if val is None:
                continue
            validity_total += 1
            if rule["type"] == "email":
                if re.match(r'^[^@]+@[^@]+\.[^@]+$', str(val)):
                    valid_count += 1
            elif rule["type"] == "integer":
                if rule.get("min", float('-inf')) <= val <= rule.get("max", float('inf')):
                    valid_count += 1
            elif rule["type"] == "iso_country_code":
                if re.match(r'^[A-Z]{2}$', str(val)):
                    valid_count += 1
            elif rule["type"] == "date":
                try:
                    d = datetime.strptime(str(val), "%Y-%m-%d")
                    age_days = (ref_date - d).days
                    max_age = rule.get("max_age_days", 99999)
                    if age_days <= max_age:
                        valid_count += 1
                except ValueError:
                    pass
    validity = round(valid_count / validity_total, 2) if validity_total else 0

    # Accuracy: age in range + valid country codes
    acc_total = 0
    acc_pass = 0
    for r in records:
        age = r.get("age")
        if age is not None:
            acc_total += 1
            if 0 <= age <= 120:
                acc_pass += 1
        country = r.get("country")
        if country is not None:
            acc_total += 1
            if re.match(r'^[A-Z]{2}$', str(country)) and country != "XX":
                acc_pass += 1
    accuracy = round(acc_pass / acc_total, 2) if acc_total else 0

    # Consistency: records where all present fields are internally consistent
    cons_pass = 0
    for r in records:
        consistent = True
        email = r.get("email")
        age = r.get("age")
        if email is not None and not re.match(r'^[^@]+@[^@]+\.[^@]+$', str(email)):
            consistent = False
        if age is not None and (age < 0 or age > 120):
            consistent = False
        if consistent:
            cons_pass += 1
    consistency = round(cons_pass / n, 2)

    # Timeliness: records updated within SLA
    time_pass = 0
    for r in records:
        updated = r.get("updated")
        if updated:
            d = datetime.strptime(updated, "%Y-%m-%d")
            if (ref_date - d).days <= 365:
                time_pass += 1
    timeliness = round(time_pass / n, 2)

    scores = [completeness, uniqueness, validity, accuracy, consistency, timeliness]
    overall = round(sum(scores) / len(scores), 2)

    lines = [
        "Quality Report:",
        f"  Completeness: {completeness:.2f} ({non_null}/{total_fields} fields non-null)",
        f"  Uniqueness:   {uniqueness:.2f} ({len(set(ids))}/{len(ids)} unique IDs)",
        f"  Validity:     {validity:.2f} ({valid_count}/{validity_total} pass format rules)",
        f"  Accuracy:     {accuracy:.2f} (age: {sum(1 for r in records if r.get('age') is not None and 0 <= r['age'] <= 120)}/{sum(1 for r in records if r.get('age') is not None)} in range, country: {sum(1 for r in records if r.get('country') is not None and re.match(r'^[A-Z]{2}$', str(r['country'])) and r['country'] != 'XX')}/{sum(1 for r in records if r.get('country') is not None)} valid ISO)",
        f"  Consistency:  {consistency:.2f} ({cons_pass}/{n} records internally consistent)",
        f"  Timeliness:   {timeliness:.2f} ({time_pass}/{n} updated within SLA)",
        "",
        f"  Overall Score: {overall:.2f} (weighted average)"
    ]
    return "\n".join(lines)

import sys
result = score_quality(sys.stdin.read())
print(result)
